 "Earthing up twice; apply compost.": {
  "hi": "दो बार मिट्टी चढ़ाना; कम्पोस्ट डालें।",
  "mr": "दोनदा भर लावणे; कंपोस्ट द्या.",
  "ta": "இருமுறை மண் அணைத்தல்; கம்போஸ்ட் இடவும்.",
  "kn": "ಎರಡು ಬಾರಿ ಮಣ್ಣು ಏರಿಸಿ; ಕಾಂಪೋಸ್ಟ್ ಹಾಕಿ.",
  "ml": "രണ്ടു തവണ മണ്ണ് കൂട്ടുക; കമ്പോസ്റ്റ് ഇടുക.",
  "te": "రెండుసార్లు మట్టి ఎగదోయండి; కంపోస్టు వేయండి.",
  "bn": "দুবার মাটি তুলে দিন; কম্পোস্ট দিন।",
  "gu": "બે વાર માટી ચઢાવો; કમ્પોસ્ટ આપો.",
  "pa": "ਦੋ ਵਾਰ ਮਿੱਟੀ ਚੜ੍ਹਾਉਣਾ; ਖਾਦ ਪਾਓ।"
 },
 "Eastern UP grows basmati in Hardoi, Lakhimpur districts.": {
  "hi": "पूर्वी उत्तर प्रदेश में हरदोई, लखीमपुर जिलों में बासमती होती है।",
  "mr": "पूर्व UP मध्ये हरदोई, लखीमपूर जिल्ह्यांत बासमती पिकते.",
  "ta": "கிழக்கு UP, Hardoi, Lakhimpur மாவட்டங்களில் basmati பயிரிடுகிறது.",
  "kn": "ಪೂರ್ವ ಉತ್ತರಪ್ರದೇಶ Hardoi, Lakhimpur ಜಿಲ್ಲೆಗಳಲ್ಲಿ ಬಾಸ್ಮತಿ ಬೆಳೆಯುತ್ತದೆ.",
  "ml": "കിഴക്കൻ ഉത്തർപ്രദേശിൽ ഹർദോയ്, ലഖിംപൂർ ജില്ലകളിൽ ബസ്മതി കൃഷി.",
  "te": "తూర్పు UP లో హర్దోయి, లఖింపూర్ జిల్లాల్లో బాస్మతి పండిస్తారు.",
  "bn": "পূর্ব UP-তে Hardoi, Lakhimpur জেলায় বাসমতি চাষ হয়।",
  "gu": "પૂર્વ UP હરદોઈ, લખીમપુર જિલ્લામાં બાસમતી પકવે છે.",
  "pa": "ਪੂਰਬੀ UP Hardoi, Lakhimpur ਜ਼ਿਲ੍ਹਿਆਂ ਵਿੱਚ basmati ਉਗਾਉਂਦਾ ਹੈ।"
 },
 "Egg Hatching": {
  "hi": "अंडे से बच्चे निकलना",
  "mr": "अंडी उबवणे",
  "ta": "முட்டை பொரித்தல்",
  "kn": "ಮೊಟ್ಟೆ ಒಡೆಯುವಿಕೆ",
  "ml": "മുട്ട വിരിയൽ",
  "te": "గుడ్లు పొదగడం",
  "bn": "ডিম ফোটা",
  "gu": "ઈંડા સેવાવા",
  "pa": "ਆਂਡੇ ਫੁੱਟਣਾ"
 },
 "Ensure crust-free germination.": {
  "hi": "अंकुरण के लिए मिट्टी की पपड़ी न जमने दें।",
  "mr": "उगवणीसाठी जमिनीवर कवच धरू देऊ नका.",
  "ta": "மேல்படை இல்லாமல் முளைப்பை உறுதிசெய்யவும்.",
  "kn": "ಮಣ್ಣು ಗಟ್ಟಿಯಾಗದಂತೆ ನೋಡಿ ಮೊಳಕೆ ಬರಿಸಿ.",
  "ml": "ഉറയ്ക്കാത്ത മണ്ണിൽ മുളയ്ക്കൽ ഉറപ്പാക്കുക.",
  "te": "పెచ్చు లేకుండా మొలకెత్తేలా చూడండి.",
  "bn": "মাটির চটা ছাড়া অঙ্কুরোদগম নিশ্চিত করুন।",
  "gu": "પોપડા વગર ઊગવાની ખાતરી કરો.",
  "pa": "ਪਪੜੀ-ਰਹਿਤ ਉੱਗਣ ਯਕੀਨੀ ਬਣਾਓ।"
 },
 "Ensure even moisture for uniform germination.": {
  "hi": "एक समान अंकुरण के लिए बराबर नमी रखें।",
  "mr": "एकसारख्या उगवणीसाठी समान ओलावा ठेवा.",
  "ta": "ஒரே சீரான முளைப்புக்கு சீரான ஈரத்தை உறுதிசெய்யவும்.",
  "kn": "ಸಮನಾಗಿ ಮೊಳಕೆ ಬರಲು ಸಮ ತೇವ ಇಡಿ.",
  "ml": "ഒരുപോലെ മുളയ്ക്കാൻ ഒരേ ഈർപ്പം ഉറപ്പാക്കുക.",
  "te": "ఒకేలా మొలకెత్తడానికి సమంగా తేమ ఉంచండి.",
  "bn": "সমান অঙ্কুরোদগমের জন্য সমান আর্দ্রতা রাখুন।",
  "gu": "સરખા ઉગાવા માટે સરખો ભેજ રાખો.",
  "pa": "ਇਕਸਾਰ ਉੱਗਣ ਲਈ ਇਕਸਾਰ ਨਮੀ ਯਕੀਨੀ ਬਣਾਓ।"
 },
 "Ensure soil moisture at 7–8 cm depth.": {
  "hi": "7–8 cm गहराई तक मिट्टी में नमी रखें।",
  "mr": "7–8 cm खोलीवर मातीत ओलावा ठेवा.",
  "ta": "7–8 cm ஆழத்தில் மண் ஈரத்தை உறுதிசெய்யவும்.",
  "kn": "7–8 cm ಆಳದಲ್ಲಿ ಮಣ್ಣು ತೇವ ಇರಲಿ.",
  "ml": "7–8 cm ആഴത്തിൽ മണ്ണിന്റെ ഈർപ്പം ഉറപ്പാക്കുക.",
  "te": "7–8 cm లోతులో నేల తేమను చూడండి.",
  "bn": "7–8 cm গভীরে মাটির আর্দ্রতা রাখুন।",
  "gu": "7–8 cm ઊંડાઈએ જમીનનો ભેજ જાળવો.",
  "pa": "7–8 cm ਡੂੰਘਾਈ 'ਤੇ ਮਿੱਟੀ ਦੀ ਨਮੀ ਯਕੀਨੀ ਬਣਾਓ।"
 },
