 "FYM 25 t/ha; neem cake 1 t/ha.": {
  "hi": "FYM 25 t/ha; नीम की खली 1 t/ha।",
  "mr": "FYM 25 t/ha; निंबोळी पेंड 1 t/ha.",
  "ta": "FYM 25 t/ha; வேப்பம் புண்ணாக்கு 1 t/ha.",
  "kn": "FYM 25 t/ha; ಬೇವಿನ ಹಿಂಡಿ 1 t/ha.",
  "ml": "FYM 25 t/ha; വേപ്പിൻപിണ്ണാക്ക് 1 t/ha.",
  "te": "FYM 25 t/ha; వేప చెక్క 1 t/ha.",
  "bn": "FYM 25 t/ha; নিম খোল 1 t/ha।",
  "gu": "FYM 25 t/ha; લીમડા ખોળ 1 t/ha.",
  "pa": "FYM 25 t/ha; neem cake 1 t/ha।"
 },
 "Feed 3% of body weight; rice bran + oilcake mixture.": {
  "hi": "शरीर के वजन का 3% खिलाएँ; चावल की भूसी + खली का मिश्रण।",
  "mr": "वजनाच्या 3% खाद्य द्या; तांदळाचा कोंडा + तेल पेंड मिश्रण.",
  "ta": "உடல் எடையில் 3% தீவனம்; அரிசி தவிடு + எண்ணெய் புண்ணாக்கு கலவை.",
  "kn": "ದೇಹ ತೂಕದ 3% ಆಹಾರ; ತೌಡು + ಎಣ್ಣೆ ಹಿಂಡಿ ಮಿಶ್ರಣ.",
  "ml": "ശരീരഭാരത്തിന്റെ 3% തീറ്റ; തവിട് + പിണ്ണാക്ക് മിശ്രിതം.",
  "te": "శరీర బరువులో 3% మేత ఇవ్వండి; తవుడు + చెక్క మిశ్రమం.",
  "bn": "দেহ ওজনের 3% খাবার দিন; চালের কুঁড়া + তেলের খোল মিশ্রণ।",
  "gu": "શરીર વજનના 3% ખોરાક; ચોખાનું થૂલું + ખોળ મિશ્રણ.",
  "pa": "ਸਰੀਰ ਦੇ ਭਾਰ ਦਾ 3% ਖੁਆਓ; ਚੌਲ ਛਾਣ + ਖਲ ਮਿਸ਼ਰਣ।"
 },
 "Feed 4× daily; 30–40% protein pellets.": {
  "hi": "रोज़ 4× खिलाएँ; 30–40% प्रोटीन वाली गोलियाँ।",
  "mr": "रोज 4× खाद्य द्या; 30–40% प्रथिन गोळ्या.",
  "ta": "தினமும் 4× தீவனம்; 30–40% புரத மாத்திரைகள்.",
  "kn": "ದಿನಕ್ಕೆ 4× ಆಹಾರ; 30–40% ಪ್ರೋಟೀನ್ ಗುಳಿಗೆ.",
  "ml": "ദിവസവും 4× തീറ്റ; 30–40% പ്രോട്ടീൻ ഉരുളകൾ.",
  "te": "రోజుకు 4× మేత ఇవ్వండి; 30–40% మాంసకృత్తుల గుళికలు.",
  "bn": "দিনে 4× খাবার দিন; 30–40% প্রোটিন পেলেট।",
  "gu": "દિવસમાં 4× ખવડાવો; 30–40% પ્રોટીન ગોળી.",
  "pa": "ਰੋਜ਼ 4× ਖੁਆਓ; 30–40% ਪ੍ਰੋਟੀਨ ਗੋਲੀਆਂ।"
 },
